/**
 * Patches the wrangler.json generated by @astrojs/cloudflare to remove fields
 * that cause Cloudflare Pages deployment validation errors.
 *
 * The adapter generates a valid config for Wrangler CLI use, but Cloudflare
 * Pages' validator is stricter about certain fields:
 *   - "ASSETS" is a reserved binding name in Pages projects
 *   - "triggers" must be absent or contain only { crons: [] }
 *   - kv_namespace entries must have a non-empty "id" (Pages uses dashboard bindings)
 */

const fs = require('fs');
const path = require('path');

const WRANGLER_JSON = path.join(__dirname, '..', 'dist', 'server', 'wrangler.json');

if (!fs.existsSync(WRANGLER_JSON)) {
  console.log('No dist/server/wrangler.json found — nothing to patch.');
  process.exit(0);
}

const config = JSON.parse(fs.readFileSync(WRANGLER_JSON, 'utf8'));

// 1. "ASSETS" is a reserved binding name in Pages — remove just the binding
//    declaration but keep assets.directory so Cloudflare Pages knows where
//    to find the static files built by the adapter (dist/client/).
//    Pages automatically provides the ASSETS binding to the Worker at runtime.
if (config.assets) {
  delete config.assets.binding;
  if (Object.keys(config.assets).length === 0) {
    delete config.assets;
  }
}

// 2. Remove empty triggers object — must be absent or { crons: [] }.
delete config.triggers;

// 3. Remove all KV namespace entries — real bindings live in the dashboard.
delete config.kv_namespaces;

// 4. Pages projects cannot have both "pages_build_output_dir" and "main".
//    This file is the server Worker config so keep "main" and drop the dir.
delete config.pages_build_output_dir;

// 5. "rules" and "no_bundle" are Worker-only fields not valid for Pages.
delete config.rules;
delete config.no_bundle;

fs.writeFileSync(WRANGLER_JSON, JSON.stringify(config, null, 2), 'utf8');
console.log('✓ Patched dist/server/wrangler.json for Cloudflare Pages compatibility.');
